targets.expr:
sum by(hostname, cluster) (
    label_replace(
        container_memory_usage_bytes{cluster=~".+-network", hostname!="", hostname=~"$service_filter", container_label_com_docker_compose_project="echo"} /1024 /1024,
        "cluster", "$1", "cluster", "^(.*)-network$"
    )
) > 30000

sum by(hostname, cluster) (
    label_replace(
        rate(container_cpu_usage_seconds_total{cluster=~".+-network", hostname!="", hostname=~"$service_filter", container_label_com_docker_compose_project="echo"}[10m]) * 100,
        "cluster", "$1", "cluster", "(.*)-network$"
    )
) > 100

sum by(hostname, cluster) (
